CREATE TABLE `tbl_outgoing` (
  `id` int(11) NOT NULL,
  `brokername` varchar(60) NOT NULL,
  `plateno` varchar(20) NOT NULL,
  `boxes` int(11) NOT NULL,
  `specie` varchar(20) NOT NULL,
  `ticketno` varchar(20) NOT NULL,
  `origin` varchar(100) NOT NULL,
  `destination` varchar(200) NOT NULL,
  `timedate` varchar(60) NOT NULL,
  `person1` varchar(60) NOT NULL,
  `person2` varchar(60) NOT NULL,
  `person3` varchar(60) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=latin1 ROW_FORMAT=COMPACT;










































































ALTER TABLE `tbl_outgoing`
  ADD PRIMARY KEY (`id`);

ALTER TABLE `tbl_outgoing`
  MODIFY `id` int(11) NOT NULL AUTO_INCREMENT, AUTO_INCREMENT=17760;

